193	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 03:02:30.965439+00	2026-07-14 03:05:14.285259+00	164	{"6827": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "6828": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "6829": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "6830": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "6831": {"data": [[null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null], [null, "Có", null, null]], "type": "grid"}, "6832": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "6833": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "6834": "1. Tỷ lệ người dân, doanh nghiệp tham gia khảo sát còn thấp.\\n2. Một số đối tượng khảo sát chưa hiểu rõ mục đích, nội dung khảo sát.\\n3. Việc thu thập phiếu khảo sát còn mất nhiều thời gian, phụ thuộc vào sự phối hợp của các đơn vị.", "6835": "Hoàn thiện và chuẩn hóa quy trình điều tra, khảo sát, bảo đảm thống nhất giữa các cấp và các đơn vị.\\nĐẩy mạnh ứng dụng công nghệ thông tin, chuyển đổi số trong phát hành, thu thập, tổng hợp và phân tích phiếu khảo sát. Xây dựng cơ sở dữ liệu tập trung về kết quả điều tra, khảo sát để phục vụ theo dõi, đánh giá và khai thác lâu dài. Đơn giản hóa nội dung phiếu khảo sát, đa dạng hóa hình thức khảo sát (trực tuyến, mã QR, thiết bị di động).", "email": "", "phone": "", "agency": "Hồng Vân", "position": "", "full_name": "ks2_hongvan", "department": "Hồng Vân", "organization": "Hồng Vân"}	f	\N	f	f	2026-07-14 03:02:30.965514+00	563	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	draft
