[null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6815": {"data": [[null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null]], "type": "grid"}, "6816": {"data": [[null, "Có", null], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, null, "Không"], [null, null, "Không"]], "type": "grid"}, "6817": {"data": [[null, null, "Không"], [null, null, "Không"], [null, null, "Không"], [null, "Có", null], [null, "Có", null], [null, "Có", null]], "type": "grid"}, "6818": {"data": [[null, null, null, "Không có ý kiến"], [null, null, null, "Không có ý kiến"], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, null, null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null], [null, "Cần", null, null]], "type": "grid"}, "6819": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"], [null, null, "Không cần"]], "type": "grid"}, "6820": {"data": [[null, "Cao", null, null], [null, null, "Trung bình", null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, null, "Trung bình", null], [null, "Cao", null, null]], "type": "grid"}, "6821": "Đáp ứng", "6822": "Sau khi thực hiện mô hình chính quyền địa phương hai cấp, khối lượng công việc và số lượng hệ thống thông tin sử dụng tăng lên, trong khi hạ tầng CNTT và nguồn nhân lực chuyên trách còn hạn chế. Một số thiết bị CNTT đã xuống cấp, cấu hình thấp, chưa đáp ứng yêu cầu xử lý công việc. Hệ thống mạng nội bộ và thiết bị mạng chưa được đầu tư đồng bộ. Việc kết nối, chia sẻ dữ liệu giữa các hệ thống còn chưa hoàn toàn thông suốt, vẫn phát sinh tình trạng nhập liệu trên nhiều phần mềm. Một số ứng dụng dùng chung đôi khi hoạt động chưa ổn định, ảnh hưởng đến tiến độ giải quyết công việc. Công tác bảo đảm an toàn thông tin, sao lưu dữ liệu và giám sát an ninh mạng chủ yếu phụ thuộc vào hạ tầng dùng chung của Thành phố; đơn vị chưa có cán bộ chuyên trách CNTT và kinh phí đầu tư, bảo trì, nâng cấp hạ tầng còn hạn chế.", "6823": "Đề nghị Thành phố tiếp tục đầu tư, nâng cấp đồng bộ hạ tầng công nghệ thông tin cho cấp xã; hoàn thiện các hệ thống dùng chung theo hướng ổn định, dễ sử dụng và liên thông dữ liệu; giảm tình trạng nhập liệu nhiều lần trên các phần mềm. Tăng cường kết nối, chia sẻ dữ liệu giữa các cơ sở dữ liệu quốc gia, cơ sở dữ liệu chuyên ngành và hệ thống thông tin của Thành phố; xây dựng kho dữ liệu dùng chung phục vụ quản lý, điều hành. Quan tâm đầu tư các giải pháp bảo đảm an toàn thông tin, sao lưu dữ liệu và giám sát an ninh mạng; hỗ trợ thay thế thiết bị CNTT đã xuống cấp; tăng cường đào tạo, bồi dưỡng kỹ năng số và ứng dụng AI cho cán bộ, công chức; bố trí đầu mối hỗ trợ kỹ thuật thường xuyên để kịp thời xử lý các sự cố, bảo đảm hệ thống vận hành ổn định, thông suốt và hiệu quả.", "6824": {"data": [[null, null, "Không", "Phượng Dực"], [null, null, "Không", "Phượng Dực"], [null, "Có", null, "Phượng Dực"], [null, null, "Không", "Phượng Dực"], [null, "Có", null, "Phượng Dực"], [null, null, "Không", "Phượng Dực"], [null, null, "Không", "Phượng Dực"], [null, "Có", null, "Phượng Dực"], [null, null, "Không", "Phượng Dực"], [null, null, "Không"