315	\N	\N		Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36	2026-07-14 04:35:43.901248+00	2026-07-14 04:41:33.576933+00	248	{"6827": {"data": [[null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null], [null, "Đáp ứng tốt", null, null, null]], "type": "grid"}, "6828": {"data": [[null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null], [null, null, "Đáp ứng", null, null]], "type": "grid"}, "6829": {"data": [[null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null]], "type": "grid"}, "6830": {"data": [[null, null, "Đáp ứng", null, null], [null, null, null, "Chưa đáp ứng", null], [null, null, null, "Chưa đáp ứng", null], [null, null, "Đáp ứng", null, null]], "type": "grid"}, "6831": {"data": [[null, null, "Chưa", null], [null, null, "Chưa", null], [null, null, "Chưa", null], [null, null, "Chưa", null], [null, null, "Chưa", null], [null, null, "Chưa", null]], "type": "grid"}, "6832": {"data": [[null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null], [null, "Cần", null]], "type": "grid"}, "6833": {"data": [[null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null], [null, "Cao", null, null]], "type": "grid"}, "6834": "Một số người dân, doanh nghiệp chưa hiểu rõ mục đích, ý nghĩa của cuộc khảo sát nên chưa tích cực tham gia hoặc trả lời chưa đầy đủ.\\nTỷ lệ tham gia khảo sát trực tuyến còn thấp, nhiều người dân chưa thành thạo sử dụng thiết bị số hoặc chưa quen với hình thức khảo sát điện tử.\\nNgười dân, đặc biệt là người cao tuổi hoặc ở vùng nông thôn, còn hạn chế về kỹ năng sử dụng thiết bị thông minh.\\nCông tác theo dõi, tổng hợp kết quả và xử lý các trường hợp chưa hoàn thành khảo sát còn thực hiện thủ công, mất nhiều thời gian.", "6835": "Xây dựng giao diện \\nTăng cường khả năng liên thông, chia sẻ dữ liệu với các hệ thống dùng chung của Thành phố để giảm nhập liệu, bảo đảm tính chính xác và đồng bộ của thông tin.\\nĐảm bảo an toàn, bảo mật thông tin, phân quyền chặt chẽ theo từng cấp quản lý; lưu nhật ký truy cập, cập nhật dữ liệu và có cơ chế sao lưu, phục hồi dữ liệu.hệ thống theo hướng đơn giản, trực quan, thân thiện với người sử dụng; tối ưu cho cả máy tính và thiết bị di động, tạo thuận lợi cho người dân, tổ chức tham gia khảo sát.", "email": "", "phone": "", "agency": "Suối Hai", "position": "", "full_name": "ks2_suoihai", "department": "Suối Hai", "organization": "Suối Hai"}	f	\N	f	f	2026-07-14 04:35:43.901306+00	571	17	{"sec_mrd4pof1_5zpng": 100, "sec_mrd4q93x_dv4pa": 100, "sec_mrd4q93x_hx301": 0, "sec_mrd4q93x_nhy01": 100, "sec_mrd4q93x_osn2f": 100, "sec_mrd4ty1p_o1mrs": 100, "sec_mrd4tycl_9vajl": 100}	submitted
